import { Component, OnInit } from '@angular/core';

@Component({
  selector: 'app-polar',
  templateUrl: './polar.component.html',
  styleUrls: ['./polar.component.scss']
})

/**
 * Apex Polar Component
 */
export class PolarComponent implements OnInit {

  // bread crumb items
  breadCrumbItems!: Array<{}>;
  basicPolarChart: any;
  monochromeChart: any;

  constructor() { }

  ngOnInit(): void {
    /**
    * BreadCrumb
    */
     this.breadCrumbItems = [
      { label: 'Apexcharts' },
      { label: 'Polararea Charts', active: true }
    ];

    // Chart Color Data Get Function
    this._basicPolarChart('["--vz-primary", "--vz-success", "--vz-warning","--vz-danger", "--vz-info", "--vz-success", "--vz-primary", "--vz-body-color", "--vz-secondary"]');
    this._monochromeChart('["--vz-primary"]');

  }

  // Chart Colors Set
  private getChartColorsArray(colors:any) {
    colors = JSON.parse(colors);
    return colors.map(function (value:any) {
      var newValue = value.replace(" ", "");
      if (newValue.indexOf(",") === -1) {
        var color = getComputedStyle(document.documentElement).getPropertyValue(newValue);
            if (color) {
            color = color.replace(" ", "");
            return color;
            }
            else return newValue;;
        } else {
            var val = value.split(',');
            if (val.length == 2) {
                var rgbaColor = getComputedStyle(document.documentElement).getPropertyValue(val[0]);
                rgbaColor = "rgba(" + rgbaColor + "," + val[1] + ")";
                return rgbaColor;
            } else {
                return newValue;
            }
        }
    });
  }

   /**
 * Basic-Polar Area Chart
 */
  private _basicPolarChart(colors:any) {
    colors = this.getChartColorsArray(colors);
    this.basicPolarChart = {
      series: [14, 23, 21, 17, 15, 10, 12, 17, 21],
      chart: {
        type: "polarArea",
        width: 400,
      },
      labels: [
        "Series A",
        "Series B",
        "Series C",
        "Series D",
        "Series E",
        "Series F",
        "Series G",
        "Series H",
        "Series I",
      ],
      stroke: {
        colors: ["#fff"],
      },
      fill: {
        opacity: 0.8,
      },
      legend: {
        position: "bottom",
      },
      colors: colors,
    };
  }

  /**
 * Polar-Area Monochrome
 */
   private _monochromeChart(colors:any) {
    colors = this.getChartColorsArray(colors);
    this.monochromeChart = {
      series: [42, 47, 52, 58, 65],
      chart: {
        width: 400,
        type: "polarArea",
      },
      labels: ["Rose A", "Rose B", "Rose C", "Rose D", "Rose E"],
      fill: {
        opacity: 1,
      },
      stroke: {
        width: 1,
        colors: undefined,
      },
      yaxis: {
        show: false,
      },
      legend: {
        position: "bottom",
      },
      plotOptions: {
        polarArea: {
          rings: {
            strokeWidth: 0,
          },
          spokes: {
            strokeWidth: 0,
          },
        },
      },
      theme: {
        mode: "light",
        palette: "palette1",
        monochrome: {
          enabled: true,
          shadeTo: "light",
          color: "#405189",
          shadeIntensity: 0.6,
        },
      },
    };
  }
 

}
<!-- Start Breadcrumbs -->
<app-breadcrumbs title="Polararea Charts" [breadcrumbItems]="breadCrumbItems"></app-breadcrumbs>
<!-- End Breadcrumbs -->

<div class="row">
  <div class="col-xl-6">
      <div class="card">
          <div class="card-header">
              <h4 class="card-title mb-0">Basic Polararea Chart</h4>
          </div><!-- end card header -->

          <div class="card-body">
            <apx-chart class="apex-charts" [series]="basicPolarChart.series" [chart]="basicPolarChart.chart"
            [labels]="basicPolarChart.labels" [stroke]="basicPolarChart.stroke"
            [fill]="basicPolarChart.fill" [legend]="basicPolarChart.legend"
            [colors]="basicPolarChart.colors" dir="ltr"></apx-chart>
          </div><!-- end card-body -->
      </div><!-- end card -->
  </div>
  <!-- end col -->

  <div class="col-xl-6">
      <div class="card">
          <div class="card-header">
              <h4 class="card-title mb-0">PolarArea Monochrome</h4>
          </div><!-- end card header -->

          <div class="card-body">
            <apx-chart class="apex-charts" [series]="monochromeChart.series" [chart]="monochromeChart.chart"
            [labels]="monochromeChart.labels" [title]="monochromeChart.title"
            [theme]="monochromeChart.theme" [fill]="monochromeChart.fill" [yaxis]="monochromeChart.yaxis"
            [stroke]="monochromeChart.stroke" [legend]="monochromeChart.legend"
            [plotOptions]="monochromeChart.plotOptions" dir="ltr"></apx-chart>
          </div><!-- end card-body -->
      </div><!-- end card -->
  </div>
  <!-- end col -->
</div>
<!-- end row -->
